function zvm_version() {
  local git_info=$(git show -s --format="(%h, %ci)" 2>/dev/null)
  echo -e "$ZVM_NAME $ZVM_VERSION $git_info"
  echo -e "\e[4m$ZVM_REPOSITORY\e[0m"
  echo -e "$ZVM_DESCRIPTION"
}

# The widget wrapper
function zvm_widget_wrapper() {
  local rawfunc=$1;
  local func=$2;
  local called=$3;
  local -i retval=0
  if ! $called; then
    $rawfunc "${@:4}"
    retval=$?
  fi
  $func "${@:4}"
  [[ $retval -eq 0 ]] && retval=$?
  return $retval
}

